                    user: { connect: { id: userClient.user.id } },
                    flowType: 'success_flow',
                    context: { some_field: faker.lorem.words(3) },
                    dv: 1,
                    sender: { fingerprint: faker.random.alphaNumeric(8), dv: 1 },
